        "bibtex": "@inproceedings{DBLP:conf/acl/Cao0LMLH000QCT25,\n  author       = {Jialun Cao and\n                  Yaojie Lu and\n                  Meiziniu Li and\n                  Haoyang Ma and\n                  Haokun Li and\n                  Mengda He and\n                  Cheng Wen and\n                  Le Sun and\n                  Hongyu Zhang and\n                  Shengchao Qin and\n                  Shing{-}Chi Cheung and\n                  Cong Tian},\n  editor       = {Wanxiang Che and\n                  Joyce Nabende and\n                  Ekaterina Shutova and\n                  Mohammad Taher Pilehvar},\n  title        = {From Informal to Formal - Incorporating and Evaluating LLMs on Natural\n                  Language Requirements to Verifiable Formal Proofs},\n  booktitle    = {Proceedings of the 63rd Annual Meeting of the Association for Computational\n                  Linguistics (Volume 1: Long Papers), {ACL} 2025, Vienna, Austria,\n                  July 27 - August 1, 2025},\n  pages        = {26984--27003},\n  publisher    = {Association for Computational Linguistics},\n  year         = {2025},\n  url          = {https://aclanthology.org/2025.acl-long.1310/},\n  timestamp    = {Tue, 24 Mar 2026 00:00:00 +0100},\n  biburl       = {https://dblp.org/rec/conf/acl/Cao0LMLH000QCT25.bib},\n  bibsource    = {dblp computer science bibliography, https://dblp.org}\n}",
